#include<bits/stdc++.h>
using namespace std;
long long n,m,t[200010];
long long calc(long long x,long long y)
{
    if(x<1||x>n||y<1||y>n)
    {
        return 0;
    }
    return max(0ll,t[x]-t[y]+m);
}
int main()
{
    scanf("%lld%lld",&n,&m);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&t[i]);
    }
    sort(t+1,t+1+n);
    long long sum=0,ans=0;
    for(long long i=1;i<=n;i++)
    {
        sum+=max(0ll,m-calc(i-1,i)-calc(i,i+1));
    }
    for(long long i=1;i<=n;i++)
    {
        long long tmp=m-max(0ll,m-calc(i-1,i)-calc(i,i+1));
        tmp+=max(0ll,calc(i-1,i)-calc(i-2,i)-calc(i-1,i+1));
        tmp+=max(0ll,calc(i,i+1)-calc(i,i+2)-calc(i-1,i+1));
        ans=max(ans,sum+tmp);
    }
    printf("%lld",ans);
    return 0;
}
